const raw = $input.first().json;
let text = '';
if (raw.content && raw.content.parts) {
  text = raw.content.parts[0].text;
} else if (typeof raw === 'string') {
  text = raw;
} else if (raw.text) {
  text = raw.text;
} else {
  text = JSON.stringify(raw);
}

function cleanGeminiJson(raw) {
  let s = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const first = s.indexOf('{');
  const last = s.lastIndexOf('}');
  if (first !== -1 && last > first) {
    s = s.substring(first, last + 1);
  }
  let result = '';
  let inStr = false;
  let esc = false;
  for (let i = 0; i < s.length; i++) {
    const c = s[i];
    if (esc) { result += c; esc = false; continue; }
    if (c === '\\' && inStr) { result += c; esc = true; continue; }
    if (c === '"') { inStr = !inStr; result += c; continue; }
    if (inStr) {
      if (c === '\n' || c === '\r') { result += ' '; continue; }
      if (c === '\t') { result += ' '; continue; }
      if (c.charCodeAt(0) < 0x20) { continue; }
    }
    result += c;
  }
  result = result.replace(/,(\s*[}\]])/g, '$1');
  return result;
}

let cleanText = cleanGeminiJson(text);
let data;

try {
  data = JSON.parse(cleanText);
} catch (e1) {
  try {
    let fixed = cleanText
      .replace(/[\u201C\u201D\u201E\u201F\u2033\u2036]/g, '"')
      .replace(/[\u2018\u2019\u201A\u201B\u2032\u2035]/g, "'")
      .replace(/^\uFEFF/, '');
    data = JSON.parse(fixed);
  } catch (e2) {
    const posMatch = e1.message.match(/position (\d+)/);
    const pos = posMatch ? parseInt(posMatch[1]) : 0;
    const start = Math.max(0, pos - 80);
    const end = Math.min(cleanText.length, pos + 80);
    const around = cleanText.substring(start, end);
    throw new Error(
      `JSON 파싱 실패: ${e1.message}\n` +
      `--- 에러 위치(${pos}) 주변 ---\n${around}\n` +
      `처음 300자: ${cleanText.substring(0, 300)}`
    );
  }
}

// images + subtitles 검증
if (!data.images || data.images.length < 4) {
  throw new Error('images must have at least 4 items, got: ' + (data.images?.length || 0));
}
if (!data.subtitles || data.subtitles.length < 6) {
  throw new Error('subtitles must have at least 6 items, got: ' + (data.subtitles?.length || 0));
}

const VALID_MOODS = ['thinking', 'excited', 'shocked', 'sad', 'angry', 'cool', 'celebrating', 'snacking', 'speechless', 'smoking', 'disappointed', 'thumbsup', 'crying', 'desperate', 'bored', 'suspicious', 'money', 'laughing', 'confident', 'scared'];

data.images = data.images.map((img, idx) => {
  if (!img.visual_type || !['image', 'meme'].includes(img.visual_type)) {
    img.visual_type = 'image';
  }
  if (img.visual_type === 'meme') {
    if (!img.meme_mood || !VALID_MOODS.includes(img.meme_mood)) {
      img.meme_mood = VALID_MOODS[idx % VALID_MOODS.length];
    }
  } else {
    img.meme_mood = '';
    if (!img.keyword) {
      img.keyword = 'abstract background';
    }
  }
  return img;
});

// === v15: 카테고리별 금지단어 검증 ===
const category = $('주제 파싱').first().json.category || 1;
const FORBIDDEN_WORDS = {
  1: ['포인트', '돌림판', '복권', '기프티콘', '앱테크', '잭팟', '방송', '스트리머', '스포츠', '분석', '픽'],
  2: ['먹튀', '패널티', '검증', '롤링', '출금', '충전', '잭팟', '대박', '당첨', '방송', '스트리머', '스포츠', '분석'],
  3: ['먹튀', '패널티', '검증', '롤링', '출금', '포인트', '돌림판', '복권', '기프티콘', '앱테크', '방송', '스트리머', '스포츠', '분석'],
  4: ['먹튀', '패널티', '검증', '포인트', '돌림판', '복권', '기프티콘', '앱테크', '잭팟', '스포츠', '분석', '픽'],
  5: ['먹튀', '패널티', '검증', '포인트', '돌림판', '복권', '기프티콘', '앱테크', '잭팟', '방송', '스트리머']
};

const forbidden = FORBIDDEN_WORDS[category] || [];
const allSubText = data.subtitles.join(' ').replace(/<[^>]*>?/gm, '');
const foundForbidden = forbidden.filter(w => allSubText.includes(w));
if (foundForbidden.length > 0) {
  throw new Error(`카테고리 ${category} 금지단어 위반! [${foundForbidden.join(', ')}] 발견. 재생성 필요.`);
}

// === v15: 마지막 자막 문장 완결 검증 (종결어미 기반) ===
const lastSub = data.subtitles[data.subtitles.length - 1].replace(/<[^>]*>?/gm, '').replace(/[!?~.]/g, '').trim();
const KOREAN_ENDINGS = ['해', '봐', '야', '마', '요', '자', '지', '너', '됨', '임', '음', '거', '든', '죠', '세요', '가'];
const lastChar = lastSub.slice(-1);
const lastTwo = lastSub.slice(-2);
const hasEnding = KOREAN_ENDINGS.some(e => lastSub.endsWith(e));
const isTooShort = lastSub.length < 4;
if (!hasEnding || isTooShort) {
  // 종결어미 없거나 너무 짧으면 → 에러 던져서 재생성 유도
  console.log('마지막 자막 미완성 감지: ' + lastSub);
  // 자동 보정하지 않고 경고만 (AI가 자유롭게 생성하도록)
}

// AI 생성 CTA 우선, 없거나 짧으면 고정 CTA fallback
const aiCta = data.outro_cta || '';
const fixedCta = $('주제 파싱').first().json.outroCta || '';
const finalCta = (aiCta.length >= 5 && aiCta.length <= 30) ? aiCta : fixedCta;

const fullDialogue = data.subtitles.join(' ');
const memeCount = data.images.filter(i => i.visual_type === 'meme').length;
const imageCount = data.images.filter(i => i.visual_type === 'image').length;

return [{
  json: {
    hook_title: data.hook_title,
    images: data.images,
    subtitles: data.subtitles,
    Subject: data.Subject,
    Caption: data.Caption,
    Comment: data.Comment,
    fullDialogue,
    Narration: fullDialogue,
    imageCount: data.images.length,
    subtitleCount: data.subtitles.length,
    memeCount,
    Status: '생성 중',
    generatedAt: new Date().toISOString(),
    topic: $('주제 파싱').first().json.topic,
    category: $('주제 파싱').first().json.category,
    outroFile: $('주제 파싱').first().json.outroFile,
    outroCta: finalCta,
    subtopic: $('주제 파싱').first().json.subtopic,
    row_number: $('주제 파싱').first().json.row_number
  }
}];

const data = $('콘텐츠 파싱').first().json;
const images = data.images || [];

// images 배열만 세그먼트로 분리 (이미지 검색용)
return images.map((img, i) => ({
  json: {
    index: i,
    keyword: img.keyword || 'abstract background',
    visual_type: img.visual_type || 'image',
    meme_mood: img.meme_mood || '',
  }
}));

const items = $input.all();

return items.map(item => {
  const audioUrl = item.json.audio_url;
  const durationSec = item.json.duration_sec;
  const timestamps = item.json.timestamps || [];

  if (!audioUrl) {
    throw new Error('TTS 응답에 audio_url이 없습니다: ' + JSON.stringify(item.json));
  }

  return {
    json: {
      audio_url: audioUrl,
      duration_sec: durationSec,
      timestamps,
      ...item.json
    }
  };
});

// NCA v8: images + subtitles 분리 구조
const hookTitle = $('콘텐츠 파싱').first().json.hook_title;
const hookClean = hookTitle.replace(/<[^>]*>?/gm, '');
const subtitles = $('콘텐츠 파싱').first().json.subtitles || [];
const imageCount = $('콘텐츠 파싱').first().json.imageCount;

const ttsResult = $('TTS 결과 처리').first().json;
const mainAudioUrl = ttsResult.audio_url;
const audioDuration = ttsResult.duration_sec;
let totalDuration = audioDuration;  // v15: 패딩 제거 (검정화면 방지)

const BGM_URL = 'http://76.13.182.180:9000/audio/bgm_new.mp3';

// === 아웃트로 영상 (카테고리 결정 노드에서 사전 선택) ===
const OUTRO_BASE = 'http://76.13.182.180:9000/outro/';
const category = $('콘텐츠 파싱').first().json.category || 1;
const outroFile = $('주제 파싱').first().json.outroFile || '';
const outroCta = $('주제 파싱').first().json.outroCta || '';
const outroUrl = outroFile ? OUTRO_BASE + outroFile : '';
const SFX_MAP = {
  whoosh: 'http://76.13.182.180:9000/audio/sfx_whoosh1.mp3',
  pop: 'http://76.13.182.180:9000/audio/sfx_pop_user.mp3',
  ding: 'http://76.13.182.180:9000/audio/sfx_ding1.mp3',
  ding2: 'http://76.13.182.180:9000/audio/sfx_ding2.mp3',
  ppook: 'http://76.13.182.180:9000/audio/sfx_ppook.wav',
  wow: 'http://76.13.182.180:9000/audio/sfx_wow.wav'
};

function escapeDrawtext(text) {
  if (!text) return '';
  // 이모지 제거 (NanumGothicBold에 이모지 글리프 없음)
  text = text.replace(/[\u{1F600}-\u{1F64F}\u{1F300}-\u{1F5FF}\u{1F680}-\u{1F6FF}\u{1F1E0}-\u{1F1FF}\u{2600}-\u{26FF}\u{2700}-\u{27BF}\u{FE00}-\u{FE0F}\u{1F900}-\u{1F9FF}\u{1FA00}-\u{1FA6F}\u{1FA70}-\u{1FAFF}\u{200D}\u{20E3}\u{FE0F}]/gu, '').trim();
  return text.replace(/\\/g, '\\\\').replace(/'/g, '\u2019').replace(/"/g, '\u201D').replace(/:/g, '\\:').replace(/;/g, '\\;').replace(/,/g, '\\,').replace(/\[/g, '\\[').replace(/\]/g, '\\]').replace(/\n/g, ' ');
}
function escapeDrawtextMultiline(text) {
  if (!text) return '';
  text = text.replace(/[\u{1F600}-\u{1F64F}\u{1F300}-\u{1F5FF}\u{1F680}-\u{1F6FF}\u{1F1E0}-\u{1F1FF}\u{2600}-\u{26FF}\u{2700}-\u{27BF}\u{FE00}-\u{FE0F}\u{1F900}-\u{1F9FF}\u{1FA00}-\u{1FA6F}\u{1FA70}-\u{1FAFF}\u{200D}\u{20E3}\u{FE0F}]/gu, '').trim();
  return text.replace(/\\/g, '\\\\').replace(/'/g, '\u2019').replace(/"/g, '\u201D').replace(/:/g, '\\:').replace(/;/g, '\\;').replace(/,/g, '\\,').replace(/\[/g, '\\[').replace(/\]/g, '\\]');
}
function wrapSubtitle(text, maxLen) {
  if (!text) return '';
  const noSpace = text.replace(/\s+/g, '').length;
  if (noSpace <= maxLen) return text;
  const mid = Math.floor(text.length / 2);
  let bestBreak = -1;
  let minDist = text.length;
  for (let i = 1; i < text.length - 1; i++) {
    if (text[i] === ' ' && Math.abs(i - mid) < minDist) {
      minDist = Math.abs(i - mid);
      bestBreak = i;
    }
  }
  if (bestBreak > 0) {
    return text.substring(0, bestBreak).trim() + '\n' + text.substring(bestBreak).trim();
  }
  return text.substring(0, maxLen) + '\n' + text.substring(maxLen);
}
function wrapTitleTwoLines(text) {
  if (!text || text.length <= 10) return text;
  const mid = Math.floor(text.length / 2);
  let bestBreak = -1;
  let minDist = text.length;
  // 쉼표 우선 탐색
  for (let i = 0; i < text.length; i++) {
    if (text[i] === ',' && Math.abs(i + 1 - mid) < minDist) {
      minDist = Math.abs(i + 1 - mid);
      bestBreak = i + 1;
    }
  }
  // 쉼표 없으면 중간 지점 근처 공백
  if (bestBreak === -1) {
    minDist = text.length;
    for (let i = 1; i < text.length - 1; i++) {
      if (text[i] === ' ' && Math.abs(i - mid) < minDist) {
        minDist = Math.abs(i - mid);
        bestBreak = i;
      }
    }
  }
  if (bestBreak > 0) {
    return text.substring(0, bestBreak).trim() + '\n' + text.substring(bestBreak).trim();
  }
  return text;
}

if (!subtitles || subtitles.length === 0) {
  throw new Error('subtitles 배열이 비어있습니다. 콘텐츠 파싱 결과를 확인하세요.');
}

// === 이미지: audioDuration / imageCount 균등 배분 ===
const imgResults = $('이미지 URL 추출').all();
const imgDuration = audioDuration / imageCount;
let imgSegments = [];
for (let i = 0; i < imageCount; i++) {
  const imgData = imgResults[i]?.json || {};
  const imageUrl = imgData.images?.[0]?.url || '';
  const isVideo = imgData.is_video || false;
  const visualType = imgData.visual_type || 'image';
  if (!imageUrl) throw new Error(`이미지 ${i+1} URL 없음`);
  imgSegments.push({
    index: i,
    imageUrl,
    isVideo,
    visualType,
    start: i * imgDuration,
    duration: imgDuration
  });
}

// === 긴 세그먼트 이미지 전환 분할 ===
let expandedSegments = [];
for (const seg of imgSegments) {
  const imgData = imgResults[seg.index]?.json || {};
  const allImages = (imgData.images || []).map(img => img.url).filter(Boolean);

  if (seg.duration >= 3.0 && allImages.length >= 2 && seg.visualType === 'image') {
    // 이미지 개수에 맞게 분할 (최대 3분할)
    const splitCount = Math.min(allImages.length, 3);
    const splitDur = seg.duration / splitCount;
    for (let j = 0; j < splitCount; j++) {
      expandedSegments.push({
        ...seg,
        imageUrl: allImages[j],
        isVideo: allImages[j].endsWith('.mp4'),
        start: seg.start + (j * splitDur),
        duration: splitDur
      });
    }
  } else {
    expandedSegments.push(seg);
  }
}
imgSegments = expandedSegments;

// === 자막: 하이브리드 타이밍 (TTS sentence timestamps + 글자수 비율 세부 배분) ===
const ttsTimestamps = ttsResult.timestamps || [];
const fullDialogue = $('콘텐츠 파싱').first().json.fullDialogue || subtitles.join(' ');

// 자막 메타 준비
let subMeta = subtitles.map((raw, i) => {
  const clean = raw.replace(/<[^>]*>?/gm, '');
  const chars = clean.replace(/\s+/g, '').length;
  return { index: i, raw, clean, chars, hasEm: raw.includes('<em>') };
});

// === TTS timestamps 활용 하이브리드 매핑 ===
let subSegments = [];

if (ttsTimestamps.length > 0) {
  // 1단계: fullDialogue에서 각 자막의 character offset 계산
  const cleanDialogue = fullDialogue.replace(/<[^>]*>?/gm, '');
  let subOffsets = [];
  let searchFrom = 0;
  for (const sub of subMeta) {
    const cleanText = sub.clean.replace(/\s+/g, '');
    // cleanDialogue에서 공백 무시하고 위치 찾기
    let matchPos = -1;
    let charCount = 0;
    for (let j = searchFrom; j < cleanDialogue.length; j++) {
      if (cleanDialogue[j] === ' ') continue;
      if (cleanDialogue[j] === cleanText[0]) {
        // 연속 매칭 시도
        let matched = true;
        let k = 0, jj = j;
        while (k < cleanText.length && jj < cleanDialogue.length) {
          if (cleanDialogue[jj] === ' ') { jj++; continue; }
          if (cleanDialogue[jj] !== cleanText[k]) { matched = false; break; }
          k++; jj++;
        }
        if (matched && k === cleanText.length) {
          matchPos = j;
          searchFrom = jj;
          break;
        }
      }
    }
    subOffsets.push({ ...sub, charOffset: matchPos >= 0 ? matchPos : searchFrom });
  }

  // 2단계: TTS sentence별 character offset 계산
  let sentenceOffsets = [];
  let sSearchFrom = 0;
  for (const ts of ttsTimestamps) {
    const tsClean = ts.text.replace(/\s+/g, '');
    let sPos = -1;
    for (let j = sSearchFrom; j < cleanDialogue.length; j++) {
      if (cleanDialogue[j] === ' ') continue;
      let matched = true;
      let k = 0, jj = j;
      while (k < tsClean.length && jj < cleanDialogue.length) {
        if (cleanDialogue[jj] === ' ') { jj++; continue; }
        if (cleanDialogue[jj] !== tsClean[k]) { matched = false; break; }
        k++; jj++;
      }
      if (matched && k === tsClean.length) {
        sPos = j;
        sSearchFrom = jj;
        break;
      }
    }
    sentenceOffsets.push({
      text: ts.text,
      offset: ts.offset,
      duration: ts.duration,
      charStart: sPos >= 0 ? sPos : sSearchFrom,
      charEnd: sSearchFrom
    });
  }

  // 3단계: 각 자막을 TTS sentence에 매핑
  for (const sub of subOffsets) {
    let bestSentence = sentenceOffsets[sentenceOffsets.length - 1];
    for (const sent of sentenceOffsets) {
      if (sub.charOffset >= sent.charStart && sub.charOffset < sent.charEnd) {
        bestSentence = sent;
        break;
      }
    }
    sub.sentence = bestSentence;
  }

  // 4단계: sentence별 그룹핑 → 글자수 비율로 세부 배분
  let sentenceGroups = {};
  for (const sub of subOffsets) {
    const key = sub.sentence.charStart;
    if (!sentenceGroups[key]) {
      sentenceGroups[key] = { sentence: sub.sentence, subs: [] };
    }
    sentenceGroups[key].subs.push(sub);
  }

  for (const key of Object.keys(sentenceGroups)) {
    const group = sentenceGroups[key];
    const sentOffset = group.sentence.offset;
    const sentDur = group.sentence.duration;
    const groupChars = group.subs.reduce((s, sub) => s + sub.chars, 0);

    let groupStart = sentOffset;
    for (const sub of group.subs) {
      const ratio = groupChars > 0 ? sub.chars / groupChars : 1 / group.subs.length;
      const dur = ratio * sentDur;
      subSegments.push({
        index: sub.index,
        raw: sub.raw,
        clean: sub.clean,
        start: groupStart,
        duration: dur,
        hasEm: sub.hasEm
      });
      groupStart += dur;
    }
  }

  // index 순으로 정렬
  subSegments.sort((a, b) => a.index - b.index);

} else {
  // fallback: timestamps 없으면 기존 글자수 비율 방식
  const totalChars = subMeta.reduce((sum, s) => sum + s.chars, 0);
  let subStart = 0;
  for (let i = 0; i < subtitles.length; i++) {
    const ratio = totalChars > 0 ? subMeta[i].chars / totalChars : 1 / subtitles.length;
    const dur = ratio * audioDuration;
    subSegments.push({
      index: i,
      raw: subMeta[i].raw,
      clean: subMeta[i].clean,
      start: subStart,
      duration: dur,
      hasEm: subMeta[i].hasEm
    });
    subStart += dur;
  }
}

// === FFmpeg inputs ===
let inputs = [];
let inputIndex = 0;
const mediaInputs = [];

// 1) 이미지/영상 (4~6개)
for (const img of imgSegments) {
  if (img.isVideo) {
    inputs.push({ file_url: img.imageUrl, options: [{ option: "-stream_loop", argument: "-1" }] });
  } else {
    inputs.push({ file_url: img.imageUrl, options: [{ option: "-loop", argument: "1" }, { option: "-framerate", argument: "30" }, { option: "-t", argument: img.duration.toFixed(2) }] });
  }
  mediaInputs.push({ idx: inputIndex, isVideo: img.isVideo, duration: img.duration });
  inputIndex++;
}

// 2) 통합 TTS
const audioIdx = inputIndex;
inputs.push({ file_url: mainAudioUrl, options: [] });
inputIndex++;

// 3) BGM
const bgmIdx = inputIndex;
inputs.push({ file_url: BGM_URL, options: [{ option: "-stream_loop", argument: "-1" }] });
inputIndex++;

// 4) 아웃트로 영상 (비디오만 사용, 오디오 무시)
let outroIdx = -1;
let outroDuration = $('주제 파싱').first().json.outroDuration || 4;
if (outroUrl) {
  outroIdx = inputIndex;
  inputs.push({ file_url: outroUrl, options: [] });
  inputIndex++;
}

// 5) SFX: 이미지 전환 + 강조 em
const sfxInputs = [];
for (let i = 0; i < imgSegments.length - 1; i++) {
  const next = imgSegments[i + 1];
  let sfxType = 'ppook';
  inputs.push({ file_url: SFX_MAP[sfxType], options: [] });
  sfxInputs.push({ idx: inputIndex, type: sfxType, timeMs: Math.round(next.start * 1000) });
  inputIndex++;
}
for (const sub of subSegments) {
  if (sub.hasEm) {
    const emSfx = /\d/.test(sub.raw) ? 'ding2' : 'pop';
    inputs.push({ file_url: SFX_MAP[emSfx], options: [] });
    sfxInputs.push({ idx: inputIndex, type: emSfx, timeMs: Math.round((sub.start + 0.3) * 1000) });
    inputIndex++;
  }
}

// === FILTER COMPLEX ===
let filterParts = [];

// 비디오 스케일 + concat
for (let i = 0; i < imgSegments.length; i++) {
  const m = mediaInputs[i];
  if (m.isVideo) {
    filterParts.push(`[${m.idx}:v]trim=duration=${m.duration.toFixed(2)},setpts=PTS-STARTPTS,scale=1080:1920:force_original_aspect_ratio=decrease,pad=1080:1920:(ow-iw)/2:(oh-ih)/2:black,setsar=1,fps=30[v${i}]`);
  } else {
    filterParts.push(`[${m.idx}:v]scale=1080:1080:force_original_aspect_ratio=increase,crop=1080:1080,pad=1080:1920:(ow-iw)/2:(oh-ih)/2:black,setsar=1,fps=30[v${i}]`);
  }
}
const vLabels = imgSegments.map((_, i) => `[v${i}]`).join('');
filterParts.push(`${vLabels}concat=n=${imgSegments.length}:v=1:a=0[vconcat]`);

// 오디오
filterParts.push(`[${audioIdx}:a]atrim=duration=${audioDuration},asetpts=PTS-STARTPTS[tts_raw]`);
const bgmTotalDur = outroUrl ? totalDuration + outroDuration : totalDuration;
filterParts.push(`[${bgmIdx}:a]atrim=duration=${bgmTotalDur},asetpts=PTS-STARTPTS,afade=t=out:st=${Math.max(0, bgmTotalDur - 2)}:d=2[bgm]`);

// SFX mix
const sfxCount = sfxInputs.length;
if (sfxCount > 0) {
  for (let i = 0; i < sfxCount; i++) {
    const si = sfxInputs[i];
    filterParts.push(`[${si.idx}:a]atrim=duration=0.3,asetpts=PTS-STARTPTS,volume=0.6,adelay=${si.timeMs}|${si.timeMs}[sfx${i}]`);
  }
  const sfxMixLabels = sfxInputs.map((_, i) => `[sfx${i}]`).join('');
  filterParts.push(`${sfxMixLabels}amix=inputs=${sfxCount}:duration=longest:normalize=0[sfx_mix]`);
  filterParts.push(`[tts_raw][bgm][sfx_mix]amix=inputs=3:duration=longest:weights=1 1 0.8:normalize=0[amain]`);
} else {
  filterParts.push(`[tts_raw][bgm]amix=inputs=2:duration=longest:weights=1 1:normalize=0[amain]`);
}

// === 아웃트로 비디오 concat ===
if (outroIdx >= 0) {
  filterParts.push(`[${outroIdx}:v]scale=1080:1920:force_original_aspect_ratio=decrease,pad=1080:1920:(ow-iw)/2:(oh-ih)/2:black,setsar=1,format=yuv420p,fps=30[voutro]`);
  filterParts.push(`[vconcat]format=yuv420p[vmain_fmt]`);
  filterParts.push(`[vmain_fmt][voutro]concat=n=2:v=1:a=0[vwithoutro]`);
} else {
  filterParts.push(`[vconcat]null[vwithoutro]`);
}

// === 오디오: 메인만 사용, 아웃트로 구간은 무음 패딩 ===
if (outroIdx >= 0) {
  const fullDuration = totalDuration + outroDuration;
  filterParts.push(`[amain]apad=whole_dur=${fullDuration.toFixed(2)}[afinal]`);
} else {
  filterParts.push(`[amain]anull[afinal]`);
}

// 자막 오버레이 (상단 제목 + 하단 자막 + 훅)
let overlayFilter = `[vwithoutro]drawbox=y=40:w=1080:h=280:color=#000000@1.0:t=fill:enable='between(t,0,${audioDuration})',drawtext=expansion=none:text='${escapeDrawtextMultiline(wrapTitleTwoLines(hookClean))}':fontsize=72:fontcolor=white:fontfile=/usr/share/fonts/truetype/nanum/NanumGothicBold.ttf:x=(w-tw)/2:y=120:line_spacing=12:enable='between(t,0,${audioDuration})'`;

// 자막 (글자수 비율 기반 타이밍, 이미지 전환과 독립)
for (const sub of subSegments) {
  const subText = escapeDrawtextMultiline(wrapSubtitle(sub.clean, 12));
  const startT = sub.start.toFixed(2);
  const endT = (sub.start + sub.duration).toFixed(2);
  overlayFilter += `,drawtext=expansion=none:text='${subText}':fontsize=70:fontcolor=white:fontfile=/usr/share/fonts/truetype/nanum/NanumGothicBold.ttf:x=(w-tw)/2:y=h-280:borderw=4:bordercolor=black:enable='between(t,${startT},${endT})'`;
}

// 훅 자막
const hookEscaped = escapeDrawtextMultiline(wrapTitleTwoLines(hookClean));
const hookEndT = 2.5;
overlayFilter += `,drawbox=y=(h-400)/2:w=1080:h=400:color=#000000@0.7:t=fill:enable='between(t,0,${hookEndT})'`;
overlayFilter += `,drawtext=expansion=none:text='${hookEscaped}':fontsize=75:fontcolor=#CCFF00:fontfile=/usr/share/fonts/truetype/nanum/NanumGothicBold.ttf:x=(w-tw)/2:y=(h-th)/2:borderw=4:bordercolor=black:enable='between(t,0,${hookEndT})'`;
// 아웃트로 CTA 자막 (아웃트로 구간에만 표시)
if (outroIdx >= 0) {
  totalDuration += outroDuration;  // CTA 계산 전에 아웃트로 길이 반영
  const ctaText = escapeDrawtextMultiline(wrapSubtitle(outroCta, 14));
  const outroStartT = (totalDuration - outroDuration).toFixed(2);
  const outroEndT = totalDuration.toFixed(2);
  overlayFilter += `,drawbox=y=h-350:w=1080:h=120:color=#000000@0.7:t=fill:enable='between(t,${outroStartT},${outroEndT})'`;
  overlayFilter += `,drawtext=expansion=none:text='${ctaText}':fontsize=60:fontcolor=#CCFF00:fontfile=/usr/share/fonts/truetype/nanum/NanumGothicBold.ttf:x=(w-tw)/2:y=h-320:borderw=3:bordercolor=black:enable='between(t,${outroStartT},${outroEndT})'`;
}

overlayFilter += '[vfinal]';
filterParts.push(overlayFilter);

const nca_payload = {
  inputs,
  filters: [{ filter: filterParts.join(';') }],
  outputs: [{
    options: [
      { option: "-map", argument: "[vfinal]" }, { option: "-map", argument: "[afinal]" },
      { option: "-c:v", argument: "libx264" }, { option: "-preset", argument: "fast" }, { option: "-crf", argument: "23" },
      { option: "-c:a", argument: "aac" }, { option: "-b:a", argument: "192k" },
      { option: "-pix_fmt", argument: "yuv420p" }, { option: "-movflags", argument: "+faststart" }, { option: "-t", argument: totalDuration.toFixed(2) }
    ],
    file_name: "kkultip_shorts_final.mp4"
  }]
};

return [{
  json: {
    nca_payload,
    totalDuration,
    imageCount: imgSegments.length,
    subtitleCount: subSegments.length,
    hookTitle,
    subject: $('콘텐츠 파싱').first().json.Subject,
    caption: $('콘텐츠 파싱').first().json.Caption,
    comment: $('콘텐츠 파싱').first().json.Comment,
    category,
    outroFile,
    debugCategory: {
      from_contentParsing: $('콘텐츠 파싱').first().json.category,
      from_topicParsing: $('주제 파싱').first().json.category,
      usedCategory: category,
      selectedOutro: outroFile || 'none',
      selectedCta: outroCta || 'none'
    }
  }
}];

// NCA 결과 처리
const result = $input.first().json;
const prevData = $('NCA 데이터 준비').first().json;

let videoUrl = '';
if (Array.isArray(result.response)) {
  videoUrl = result.response[0]?.file_url || '';
} else if (typeof result.response === 'string') {
  videoUrl = result.response;
} else {
  videoUrl = result.output_url || result.url || result.video_url || result.file_url || '';
}

if (!videoUrl) {
  throw new Error('NCA 영상 제작 결과 URL 없음: ' + JSON.stringify(result).substring(0, 500));
}

return [{
  json: {
    '영상 URL': videoUrl,
    Status: '완료',
    topic: $('주제 파싱').first().json.topic,
    category: prevData.category,
    outro_file: prevData.outroFile || '',
  }
}];

const raw = $input.first().json;
let text = '';
if (raw.content && raw.content.parts) {
  text = raw.content.parts[0].text;
} else if (typeof raw === 'string') {
  text = raw;
} else if (raw.text) {
  text = raw.text;
} else {
  text = JSON.stringify(raw);
}

const cleanText = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
const data = JSON.parse(cleanText);

if (!data.topic) {
  throw new Error('AI 주제 생성 결과에 topic이 없습니다: ' + cleanText);
}

const catNode = $('카테고리 결정').first().json;
return [{
  json: {
    topic: data.topic,
    category: catNode.category,
    outroFile: catNode.outroFile,
    outroCta: catNode.outroCta,
    outroDuration: catNode.outroDuration,
    subtopic: catNode.subtopic,
    row_number: null
  }
}];

// 카테고리 순차 순환 - Google Sheets 행 수 기반 카운터
const sheetRows = $('카운터 읽기').all();
const counter = sheetRows.length;  // 시트에 기록된 행 수 = 지금까지 실행된 횟수

const OUTRO_VIDEOS = {
  1: [
    { file: 'partner_site.mp4', duration: 3.5, cta: '검증된 제휴사이트에서 이용하세요', subtopic: '검증된 제휴사이트 이용 방법' },
    { file: 'scam_report.mp4', duration: 3.0, cta: '먹튀 확인하고 거르세요', subtopic: '먹튀 제보와 검증 과정' }
  ],
  2: [
    { file: 'pointzone_game.mp4', duration: 4.53, cta: '포인트로 다양한 게임 즐기세요', subtopic: '포인트존 게임으로 포인트 모으는 방법' },
    { file: 'pointzone_lottery.mp4', duration: 5.36, cta: '복권으로 포인트 모아보세요', subtopic: '복권으로 포인트 적립하는 방법' },
    { file: 'pointzone_spin.mp4', duration: 4.07, cta: '돌림판으로 포인트 모아보세요', subtopic: '돌림판으로 포인트 모으는 방법' },
    { file: 'gifticon.mp4', duration: 2.5, cta: '포인트로 기프티콘 교환하세요', subtopic: '포인트를 기프티콘으로 교환하는 방법' }
  ],
  3: [
    { file: 'jackpot_report.mp4', duration: 3.77, cta: '잭팟 제보하면 포인트 5천 지급!', subtopic: '잭팟 당첨 사례와 제보 방법' },
    { file: 'best_post.mp4', duration: 3.87, cta: '베스트 글 올리고 포인트 받자!', subtopic: '커뮤니티 베스트 글과 유저 참여' }
  ],
  4: [
    { file: 'highlight.mp4', duration: 2.77, cta: '놓친 방송 하이라이트 챙겨보세요', subtopic: '스트리머 방송 명장면 하이라이트' },
    { file: 'live_broadcast.mp4', duration: 4.7, cta: '온카스터디 방송존에서 실시간 소통하세요', subtopic: '실시간 방송존에서 스트리머와 소통' }
  ],
  5: [
    { file: 'sports_news.mp4', duration: 3.43, cta: '최신 스포츠 뉴스 확인하세요', subtopic: '최신 스포츠 뉴스' },
    { file: 'casino_news.mp4', duration: 3.2, cta: '최신 카지노 뉴스 확인하세요', subtopic: '최신 카지노/게임사 뉴스' },
    { file: 'sports_analysis.mp4', duration: 3.5, cta: '스포츠 분석으로 적중률 올리세요', subtopic: '스포츠 경기 분석과 픽' }
  ]
};

const sequence = [];
for (let cat = 1; cat <= 5; cat++) {
  const list = OUTRO_VIDEOS[cat];
  for (let idx = 0; idx < list.length; idx++) {
    sequence.push({ category: cat, index: idx });
  }
}

const current = sequence[counter % sequence.length];
const category = current.category;
const picked = OUTRO_VIDEOS[category][current.index];

return [{ json: {
  category,
  outroFile: picked.file,
  outroCta: picked.cta,
  subtopic: picked.subtopic,
  outroDuration: picked.duration,
  sequenceInfo: `${counter + 1}/13 (카테고리${category}: ${picked.subtopic})`
}}];
